def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=np.float64)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 8):
            base_term = ((-1) ** j) * (ratio ** j) / (j + 0.5)
            if j % 3 == 0:
                base_term *= 2.0
            elif j % 2 == 0:
                base_term *= 1.25
            else:
                base_term *= 0.85
            score += base_term
        if capacity < item * 1.1:
            score *= 4
            for k in range(1, 5):
                add_term = ((-1) ** (k+1)) * (ratio ** (k+6)) / (k+4)
                if k % 2 == 0:
                    add_term += np.exp(-ratio * k)
                else:
                    add_term -= np.sqrt(ratio + k)
                score += add_term
        elif capacity < item * 1.8:
            score *= 1.8
            for k in range(4):
                trig_term = np.sin(ratio * (k+2)) / (k+2)
                if k % 2 == 0:
                    trig_term += np.cos(ratio * (k+3)) / (k+3)
                else:
                    trig_term -= np.tan(ratio / (k+1) + 0.1)
                score += trig_term
        elif capacity > item * 3.5:
            score /= 2.5
            for k in range(3, 7):
                log_term = np.log1p(ratio * k) / (k + 2)
                if k % 2 == 1:
                    log_term *= -1.5
                else:
                    log_term *= 1.2
                score += log_term
            if score < 0:
                score = abs(score) ** 0.7
        else:
            for k in range(1, 5):
                cos_term = (ratio ** k) * np.cos(k * ratio) / (k + 1)
                sin_term = (ratio ** (k+1)) * np.sin((k+1) * ratio) / (k + 2)
                score += cos_term - sin_term
            if np.isclose(score, 0, atol=1e-6):
                score = 1e-3
        if score == 0 or np.isnan(score) or np.isinf(score):
            priorities[i] = np.inf
        else:
            priorities[i] = -score
    return priorities
